import {getItemIndexByCharacterKey} from '../utils'
import reducer from '../reducer'

describe('getItemIndexByCharacterKey', () => {
  const items = ['a', 'b', 'aba', 'aab', 'bab']
  const itemToString = jest.fn().mockImplementation(item => item)
  const isItemDisabled = jest.fn().mockReturnValue(false)

  test('returns to check from start if from highlightedIndex does not find anything', () => {
    const index = getItemIndexByCharacterKey({
      keysSoFar: 'a',
      highlightedIndex: 3,
      items,
      itemToString,
      isItemDisabled,
    })
    expect(index).toBe(0)
  })

  test('checks from highlightedIndex position inclusively if there is more than one key', () => {
    const index = getItemIndexByCharacterKey({
      keysSoFar: 'aba',
      highlightedIndex: 2,
      items,
      itemToString,
      isItemDisabled,
    })
    expect(index).toBe(2)
  })

  test('checks from highlightedIndex position exclusively if there is only one key', () => {
    const index = getItemIndexByCharacterKey({
      keysSoFar: 'a',
      highlightedIndex: 2,
      items,
      itemToString,
      isItemDisabled,
    })
    expect(index).toBe(3)
  })

  test('skips disabled item and moves to next', () => {
    const keysSoFar = 'b'
    const highlightedIndex = 0

    expect(
      getItemIndexByCharacterKey({
        keysSoFar,
        highlightedIndex,
        items,
        itemToString,
        isItemDisabled: jest
          .fn()
          .mockImplementation((_item, index) => index === 1),
      }),
    ).toEqual(4)
  })
})

test('reducer throws error if called without proper action type', () => {
  expect(() => {
    reducer({}, {type: 'super-bogus'})
  }).toThrowError('Reducer called without proper action type.')
})

import {renderHook} from '@testing-library/react'
import {
  defaultProps,
  getInitialValue,
  getDefaultValue,
  useMouseAndTouchTracker,
  getItemAndIndex,
  isDropdownsStateEqual,
} from '../utils'

describe('utils', () => {
  describe('itemToString', () => {
    test('returns empty string if item is falsy', () => {
      const emptyString = defaultProps.itemToString(null)
      expect(emptyString).toBe('')
    })
  })

  describe('getItemAndIndex', () => {
    test('returns arguments if passed as defined', () => {
      expect(getItemAndIndex({}, 5, [])).toEqual([{}, 5])
    })

    test('throws an error when item and index are not passed', () => {
      const errorMessage = 'Pass either item or index to the item getter prop!'

      expect(() =>
        getItemAndIndex(undefined, undefined, [1, 2, 3], errorMessage),
      ).toThrowError(errorMessage)
    })

    test('returns index if item is passed', () => {
      const item = {}

      expect(getItemAndIndex(item, undefined, [{x: 1}, item, {x: 2}])).toEqual([
        item,
        1,
      ])
    })

    test('returns item if index is passed', () => {
      const index = 2
      const item = {x: 2}
      expect(getItemAndIndex(undefined, 2, [{x: 1}, {x: 3}, item])).toEqual([
        item,
        index,
      ])
    })
  })

  test('getInitialValue will not return undefined as initial value', () => {
    const defaults = {bogusValue: 'hello'}
    const value = getInitialValue(
      {initialBogusValue: undefined},
      'bogusValue',
      defaults,
    )

    expect(value).toEqual(defaults.bogusValue)
  })

  test('getInitialValue will not return undefined as value', () => {
    const defaults = {bogusValue: 'hello'}
    const value = getInitialValue(
      {bogusValue: undefined},
      'bogusValue',
      defaults,
    )

    expect(value).toEqual(defaults.bogusValue)
  })

  test('getDefaultValue will not return undefined as value', () => {
    const defaults = {bogusValue: 'hello'}
    const value = getDefaultValue(
      {defaultBogusValue: undefined},
      'bogusValue',
      defaults,
    )

    expect(value).toEqual(defaults.bogusValue)
  })

  describe('useMouseAndTouchTracker', () => {
    test('renders without error', () => {
      expect(() => {
        renderHook(() => useMouseAndTouchTracker(undefined, [], jest.fn()))
      }).not.toThrowError()
    })

    test('adds and removes listeners to environment', () => {
      const environment = {
        addEventListener: jest.fn(),
        removeEventListener: jest.fn(),
      }
      const refs = []
      const handleBlur = jest.fn()

      const {unmount, rerender, result} = renderHook(() =>
        useMouseAndTouchTracker(environment, refs, handleBlur),
      )

      expect(environment.addEventListener).toHaveBeenCalledTimes(5)
      expect(environment.addEventListener).toHaveBeenCalledWith(
        'mousedown',
        expect.any(Function),
      )
      expect(environment.addEventListener).toHaveBeenCalledWith(
        'mouseup',
        expect.any(Function),
      )
      expect(environment.addEventListener).toHaveBeenCalledWith(
        'touchstart',
        expect.any(Function),
      )
      expect(environment.addEventListener).toHaveBeenCalledWith(
        'touchmove',
        expect.any(Function),
      )
      expect(environment.addEventListener).toHaveBeenCalledWith(
        'touchend',
        expect.any(Function),
      )
      expect(environment.removeEventListener).not.toHaveBeenCalled()

      rerender()

      expect(environment.removeEventListener).not.toHaveBeenCalled()

      unmount()

      expect(environment.addEventListener).toHaveBeenCalledTimes(5)
      expect(environment.removeEventListener).toHaveBeenCalledTimes(5)
      expect(environment.removeEventListener).toHaveBeenCalledWith(
        'mousedown',
        expect.any(Function),
      )
      expect(environment.removeEventListener).toHaveBeenCalledWith(
        'mouseup',
        expect.any(Function),
      )
      expect(environment.removeEventListener).toHaveBeenCalledWith(
        'touchstart',
        expect.any(Function),
      )
      expect(environment.removeEventListener).toHaveBeenCalledWith(
        'touchmove',
        expect.any(Function),
      )
      expect(environment.removeEventListener).toHaveBeenCalledWith(
        'touchend',
        expect.any(Function),
      )

      expect(result.current).toEqual({
        isMouseDown: false,
        isTouchMove: false,
        isTouchEnd: false,
      })
    })
